#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <stdbool.h>
#define MAXN 100005
#define INF 1000000000

int pos[10][MAXN];
int posSize[10];
int distArr[MAXN];
bool visited[MAXN];
char s[MAXN];
int n;

void bfs() {
    int q[MAXN];
    int head = 0, tail = 0;
    q[tail++] = 0;
    distArr[0] = 0;
    while (head < tail) {
        int u = q[head++];
        if (visited[u]) continue;
        visited[u] = true;
        int d = s[u] - '0';
        // same digit jumps
        for (int i = 0; i < posSize[d]; ++i) {
            int v = pos[d][i];
            if (distArr[v] > distArr[u] + 1) {
                distArr[v] = distArr[u] + 1;
                q[tail++] = v;
            }
        }
        posSize[d] = 0; // clear to avoid future work
        // neighbour i-1
        if (u - 1 >= 0 && distArr[u-1] > distArr[u] + 1) {
            distArr[u-1] = distArr[u] + 1;
            q[tail++] = u-1;
        }
        // neighbour i+1
        if (u + 1 < n && distArr[u+1] > distArr[u] + 1) {
            distArr[u+1] = distArr[u] + 1;
            q[tail++] = u+1;
        }
    }
}

int main() {
    scanf("%s", s);
    n = strlen(s);
    // reset structures
    for (int d = 0; d < 10; ++d) posSize[d] = 0;
    for (int i = 0; i < n; ++i) {
        int d = s[i] - '0';
        pos[d][posSize[d]++] = i;
        distArr[i] = INF;
        visited[i] = false;
    }
    bfs();
    printf("%d\n", distArr[n-1]);
    return 0;
}

