#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string s; cin >> s;
    int n = s.size();
    vector<int> pos[10];
    for(int i=0;i<n;++i) pos[s[i]-'0'].push_back(i);
    const int INF = 1e9;
    vector<int> dist(n, INF);
    vector<char> vis(n, 0);
    queue<int> q;
    q.push(0);
    dist[0]=0;
    while(!q.empty()) {
        int u=q.front(); q.pop();
        if(vis[u]) continue;
        vis[u]=1;
        int d=s[u]-'0';
        for(int v:pos[d]) {
            if(dist[v] > dist[u]+1) {
                dist[v]=dist[u]+1;
                q.push(v);
            }
        }
        pos[d].clear();
        if(u-1>=0 && dist[u-1]>dist[u]+1) {dist[u-1]=dist[u]+1; q.push(u-1);}            
        if(u+1<n && dist[u+1]>dist[u]+1) {dist[u+1]=dist[u]+1; q.push(u+1);}            
    }
    cout<<dist[n-1]<<"\n";
    return 0;
}

