public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String s = br.readLine().trim();
        int n = s.length();
        @SuppressWarnings("unchecked")
        ArrayList<Integer>[] pos = new ArrayList[10];
        for (int i = 0; i < 10; i++) pos[i] = new ArrayList<>();
        for (int i = 0; i < n; i++) pos[s.charAt(i) - '0'].add(i);
        int[] dist = new int[n];
        Arrays.fill(dist, Integer.MAX_VALUE);
        boolean[] vis = new boolean[n];
        ArrayDeque<Integer> q = new ArrayDeque<>();
        q.add(0);
        dist[0] = 0;
        while (!q.isEmpty()) {
            int u = q.poll();
            if (vis[u]) continue;
            vis[u] = true;
            int d = s.charAt(u) - '0';
            for (int v : pos[d]) {
                if (dist[v] > dist[u] + 1) {
                    dist[v] = dist[u] + 1;
                    q.add(v);
                }
            }
            pos[d].clear();
            if (u - 1 >= 0 && dist[u - 1] > dist[u] + 1) {
                dist[u - 1] = dist[u] + 1;
                q.add(u - 1);
            }
            if (u + 1 < n && dist[u + 1] > dist[u] + 1) {
                dist[u + 1] = dist[u] + 1;
                q.add(u + 1);
            }
        }
        System.out.println(dist[n - 1]);
    }
}

